//! `baton-metaquery` logic: search the iRODS catalog for objects that
//! match an [`AvuQuery`] / [`TimestampQuery`] / [`AccessQuery`] filter
//! and return the matching paths as [`Target`] values.
//!
//! Capabilities, in the order they were built up across Session 4c:
//!
//! - **Single-AVU search** across data objects and collections,
//!   scoped to a parent `collection` if provided.
//! - **Timestamp range queries** — `created` / `modified` filters
//!   applied as additional WHERE conditions alongside any AVU
//!   criteria.
//! - **ACL selectors** — filter by an `(owner, level [, zone])`
//!   triple via the catalog's user-access join. Data objects and
//!   collections use different join columns (`COL_USER_*` vs
//!   `COL_COLL_USER_*`), same split that bit us in Session 3b's
//!   `--acl` work.
//! - **Multi-AVU criteria** via per-AVU subqueries + result
//!   intersection. iRODS's `rcGenQuery` doesn't naturally express
//!   metadata self-joins — chaining multiple WHERE conditions on
//!   `COL_META_*_ATTR_NAME` / `COL_META_*_ATTR_VALUE` in one query
//!   asks the parser for a single AVU row that matches every pair
//!   simultaneously, which is impossible (a row has one attribute
//!   name). The fix: run one subquery per AVU, intersect the
//!   resulting path sets. Other criteria (timestamps, access, scope)
//!   ride along on every subquery.

use std::collections::HashSet;

use crate::connection::{GenQuery, RodsConnection};
use crate::error::BatonError;
use crate::ffi;
use crate::operations::list::sql_escape;
use crate::types::{
    AccessQuery, AclLevel, AvuQuery, Collection, DataObject, MetaqueryInput, Operator, Target,
    TimestampQuery,
};

/// Which kinds of objects to include in the search.
///
/// Default is "both" — matches `baton-metaquery`'s behaviour when no
/// `--obj` / `--coll` flag is given. Constructing with `Default` is
/// the right choice for a permissive search; the binary tightens this
/// when its CLI flags say to.
#[derive(Debug, Clone, Copy)]
pub struct MetaqueryFlags {
    pub include_data_objects: bool,
    pub include_collections: bool,
}

impl Default for MetaqueryFlags {
    fn default() -> Self {
        Self {
            include_data_objects: true,
            include_collections: true,
        }
    }
}

/// Search the catalog for objects matching `input`. Multiple result
/// kinds (data objects + collections) are returned in one flat
/// [`Vec`].
///
/// Single-AVU and zero-AVU inputs run as one genQuery per object
/// kind. Multi-AVU inputs run one subquery per AVU and intersect the
/// matching paths — see the per-function comments below for the why.
/// Result order is not guaranteed.
///
/// Timestamp criteria translate into WHERE conditions on the
/// `D_CREATE_TIME` / `D_MODIFY_TIME` (or `COLL_*` equivalents)
/// columns. Values are passed through unmodified — iRODS stores
/// timestamps as zero-padded epoch strings (e.g. `"01777320246"`),
/// and the caller is responsible for supplying the same form.
///
/// Access selectors filter by `(owner, level [, zone])`. Levels are
/// translated from the [`AclLevel`] enum into iRODS's verbose
/// catalog form (`read` → `"read object"`, `write` → `"modify
/// object"`, `null`/`own` pass through). The data-object path joins
/// via `COL_USER_*`; the collection path joins via `COL_COLL_USER_*`
/// — different column families because iRODS routes the join
/// through the access table that matches the queried object kind.
pub fn metaquery(
    conn: &mut RodsConnection,
    input: &MetaqueryInput,
    flags: &MetaqueryFlags,
) -> Result<Vec<Target>, BatonError> {
    // No criteria → no query. Returning every object in the catalog is
    // dangerous and not what baton does either; surface the empty
    // result and let the caller decide whether that's an error.
    if input.avus.is_empty() && input.timestamps.is_empty() && input.access.is_empty() {
        return Ok(Vec::new());
    }

    let multi_avu = input.avus.len() > 1;
    let mut results: Vec<Target> = Vec::new();

    if flags.include_data_objects {
        let part = if multi_avu {
            query_data_objects_intersect(conn, input)?
        } else {
            query_data_objects(conn, input)?
        };
        results.extend(part);
    }

    if flags.include_collections {
        let part = if multi_avu {
            query_collections_intersect(conn, input)?
        } else {
            query_collections(conn, input)?
        };
        results.extend(part);
    }

    Ok(results)
}

/// Translate an [`Operator`] into the leading token iRODS's genQuery
/// parser expects on a WHERE-clause literal. The full condition
/// string is `"<op> '<value>'"` (with the value SQL-escaped).
fn operator_token(op: Operator) -> &'static str {
    match op {
        Operator::Equals => "=",
        Operator::Like => "like",
        Operator::NotLike => "not like",
        Operator::In => "in",
        Operator::GreaterThan => ">",
        Operator::NumericGreaterThan => "n>",
        Operator::LessThan => "<",
        Operator::NumericLessThan => "n<",
        Operator::GreaterThanOrEqual => ">=",
        Operator::NumericGreaterThanOrEqual => "n>=",
        Operator::LessThanOrEqual => "<=",
        Operator::NumericLessThanOrEqual => "n<=",
    }
}

/// For an [`Operator::In`] criterion the `value` must already be the
/// parenthesised list literal iRODS expects (`('a', 'b', 'c')`); we
/// pass it through unescaped so callers can inject the structural
/// punctuation. For every other operator the value is treated as a
/// single literal and SQL-escaped.
fn condition_for(op: Operator, value: &str) -> String {
    if op == Operator::In {
        format!("{} {}", operator_token(op), value)
    } else {
        format!("{} '{}'", operator_token(op), sql_escape(value))
    }
}

fn query_data_objects(
    conn: &mut RodsConnection,
    input: &MetaqueryInput,
) -> Result<Vec<Target>, BatonError> {
    let mut q = GenQuery::new();

    q.add_select(ffi::COL_COLL_NAME as i32);
    q.add_select(ffi::COL_DATA_NAME as i32);

    apply_avu_conditions_to_data_object(&mut q, &input.avus)?;
    apply_timestamp_conditions_to_data_object(&mut q, &input.timestamps)?;
    apply_access_conditions_to_data_object(&mut q, &input.access)?;
    apply_collection_scope(&mut q, input)?;

    let rows = conn.query(&mut q)?;
    Ok(rows
        .into_iter()
        .map(|row| {
            let collection = row.first().cloned().unwrap_or_default();
            let data_object = row.get(1).cloned().unwrap_or_default();
            Target::DataObject(DataObject {
                collection,
                data_object,
                size: None,
                checksum: None,
                avus: None,
                access: None,
                replicates: None,
                timestamps: None,
                error: None,
            })
        })
        .collect())
}

/// Multi-AVU data-object search: run one subquery per AVU and
/// intersect the resulting `(collection, data_object)` paths. Each
/// subquery carries the same timestamp / access / scope criteria, so
/// they're applied uniformly. Short-circuits when the running
/// intersection becomes empty — no point doing more catalog round
/// trips when nothing can possibly match.
fn query_data_objects_intersect(
    conn: &mut RodsConnection,
    input: &MetaqueryInput,
) -> Result<Vec<Target>, BatonError> {
    let mut running: Option<HashSet<(String, String)>> = None;

    for avu in &input.avus {
        let sub_input = MetaqueryInput {
            avus: vec![avu.clone()],
            timestamps: input.timestamps.clone(),
            access: input.access.clone(),
            collection: input.collection.clone(),
            zone: input.zone.clone(),
        };
        let sub = query_data_objects(conn, &sub_input)?;
        let sub_set: HashSet<(String, String)> = sub
            .into_iter()
            .filter_map(|t| match t {
                Target::DataObject(d) => Some((d.collection, d.data_object)),
                _ => None,
            })
            .collect();

        running = Some(match running {
            None => sub_set,
            Some(prev) => prev.intersection(&sub_set).cloned().collect(),
        });

        if running.as_ref().map_or(false, |s| s.is_empty()) {
            break;
        }
    }

    Ok(running
        .unwrap_or_default()
        .into_iter()
        .map(|(collection, data_object)| {
            Target::DataObject(DataObject {
                collection,
                data_object,
                size: None,
                checksum: None,
                avus: None,
                access: None,
                replicates: None,
                timestamps: None,
                error: None,
            })
        })
        .collect())
}

fn query_collections(
    conn: &mut RodsConnection,
    input: &MetaqueryInput,
) -> Result<Vec<Target>, BatonError> {
    let mut q = GenQuery::new();

    q.add_select(ffi::COL_COLL_NAME as i32);

    apply_avu_conditions_to_collection(&mut q, &input.avus)?;
    apply_timestamp_conditions_to_collection(&mut q, &input.timestamps)?;
    apply_access_conditions_to_collection(&mut q, &input.access)?;
    apply_collection_scope(&mut q, input)?;

    let rows = conn.query(&mut q)?;
    Ok(rows
        .into_iter()
        .map(|row| {
            let collection = row.into_iter().next().unwrap_or_default();
            Target::Collection(Collection {
                collection,
                avus: None,
                access: None,
                timestamps: None,
                contents: None,
                error: None,
            })
        })
        .collect())
}

/// Multi-AVU collection search — same intersection strategy as for
/// data objects but on `Vec<String>` of collection paths.
fn query_collections_intersect(
    conn: &mut RodsConnection,
    input: &MetaqueryInput,
) -> Result<Vec<Target>, BatonError> {
    let mut running: Option<HashSet<String>> = None;

    for avu in &input.avus {
        let sub_input = MetaqueryInput {
            avus: vec![avu.clone()],
            timestamps: input.timestamps.clone(),
            access: input.access.clone(),
            collection: input.collection.clone(),
            zone: input.zone.clone(),
        };
        let sub = query_collections(conn, &sub_input)?;
        let sub_set: HashSet<String> = sub
            .into_iter()
            .filter_map(|t| match t {
                Target::Collection(c) => Some(c.collection),
                _ => None,
            })
            .collect();

        running = Some(match running {
            None => sub_set,
            Some(prev) => prev.intersection(&sub_set).cloned().collect(),
        });

        if running.as_ref().map_or(false, |s| s.is_empty()) {
            break;
        }
    }

    Ok(running
        .unwrap_or_default()
        .into_iter()
        .map(|collection| {
            Target::Collection(Collection {
                collection,
                avus: None,
                access: None,
                timestamps: None,
                contents: None,
                error: None,
            })
        })
        .collect())
}

fn apply_avu_conditions_to_data_object(
    q: &mut GenQuery,
    avus: &[AvuQuery],
) -> Result<(), BatonError> {
    for avu in avus {
        q.add_where(
            ffi::COL_META_DATA_ATTR_NAME as i32,
            &format!("= '{}'", sql_escape(&avu.attribute)),
        )?;
        q.add_where(
            ffi::COL_META_DATA_ATTR_VALUE as i32,
            &condition_for(avu.operator, &avu.value),
        )?;
        if let Some(units) = &avu.units {
            q.add_where(
                ffi::COL_META_DATA_ATTR_UNITS as i32,
                &format!("= '{}'", sql_escape(units)),
            )?;
        }
    }
    Ok(())
}

fn apply_avu_conditions_to_collection(
    q: &mut GenQuery,
    avus: &[AvuQuery],
) -> Result<(), BatonError> {
    for avu in avus {
        q.add_where(
            ffi::COL_META_COLL_ATTR_NAME as i32,
            &format!("= '{}'", sql_escape(&avu.attribute)),
        )?;
        q.add_where(
            ffi::COL_META_COLL_ATTR_VALUE as i32,
            &condition_for(avu.operator, &avu.value),
        )?;
        if let Some(units) = &avu.units {
            q.add_where(
                ffi::COL_META_COLL_ATTR_UNITS as i32,
                &format!("= '{}'", sql_escape(units)),
            )?;
        }
    }
    Ok(())
}

/// Apply each [`TimestampQuery`] as a WHERE condition on the
/// data-object create/modify columns. A query with neither `created`
/// nor `modified` set is silently a no-op.
fn apply_timestamp_conditions_to_data_object(
    q: &mut GenQuery,
    timestamps: &[TimestampQuery],
) -> Result<(), BatonError> {
    for ts in timestamps {
        if let Some(created) = &ts.created {
            q.add_where(
                ffi::COL_D_CREATE_TIME as i32,
                &condition_for(ts.operator, created),
            )?;
        }
        if let Some(modified) = &ts.modified {
            q.add_where(
                ffi::COL_D_MODIFY_TIME as i32,
                &condition_for(ts.operator, modified),
            )?;
        }
    }
    Ok(())
}

fn apply_timestamp_conditions_to_collection(
    q: &mut GenQuery,
    timestamps: &[TimestampQuery],
) -> Result<(), BatonError> {
    for ts in timestamps {
        if let Some(created) = &ts.created {
            q.add_where(
                ffi::COL_COLL_CREATE_TIME as i32,
                &condition_for(ts.operator, created),
            )?;
        }
        if let Some(modified) = &ts.modified {
            q.add_where(
                ffi::COL_COLL_MODIFY_TIME as i32,
                &condition_for(ts.operator, modified),
            )?;
        }
    }
    Ok(())
}

/// Translate an [`AclLevel`] into the iRODS catalog's stored access-name
/// string. iRODS uses verbose forms internally (`"read object"`,
/// `"modify object"`); our enum's compact serialisation (`read`,
/// `write`) is the JSON-shape variant baton emits, not what the
/// catalog matches against.
fn acl_level_to_irods_name(level: AclLevel) -> &'static str {
    match level {
        AclLevel::Null => "null",
        AclLevel::Read => "read object",
        AclLevel::Write => "modify object",
        AclLevel::Own => "own",
    }
}

/// Filter a data-object query by `(owner, level [, zone])`. Joins via
/// the data-access path; uses `COL_USER_*` columns alongside
/// `COL_DATA_ACCESS_NAME`, mirroring the data-object branch in
/// `fetch_acl` from Session 3b.
fn apply_access_conditions_to_data_object(
    q: &mut GenQuery,
    accesses: &[AccessQuery],
) -> Result<(), BatonError> {
    for a in accesses {
        q.add_where(
            ffi::COL_USER_NAME as i32,
            &format!("= '{}'", sql_escape(&a.owner)),
        )?;
        q.add_where(
            ffi::COL_DATA_ACCESS_NAME as i32,
            &format!("= '{}'", acl_level_to_irods_name(a.level)),
        )?;
        if let Some(zone) = &a.zone {
            q.add_where(
                ffi::COL_USER_ZONE as i32,
                &format!("= '{}'", sql_escape(zone)),
            )?;
        }
    }
    Ok(())
}

/// Filter a collection query by `(owner, level [, zone])`. Uses
/// `COL_COLL_USER_*` columns — different from the data-object path
/// because iRODS routes the user-name join through the
/// collection-access table when those columns appear in the SELECT
/// or WHERE list. Same split we caught the hard way in Session 3b.
fn apply_access_conditions_to_collection(
    q: &mut GenQuery,
    accesses: &[AccessQuery],
) -> Result<(), BatonError> {
    for a in accesses {
        q.add_where(
            ffi::COL_COLL_USER_NAME as i32,
            &format!("= '{}'", sql_escape(&a.owner)),
        )?;
        q.add_where(
            ffi::COL_COLL_ACCESS_NAME as i32,
            &format!("= '{}'", acl_level_to_irods_name(a.level)),
        )?;
        if let Some(zone) = &a.zone {
            q.add_where(
                ffi::COL_COLL_USER_ZONE as i32,
                &format!("= '{}'", sql_escape(zone)),
            )?;
        }
    }
    Ok(())
}

/// Restrict the search to descendants of `input.collection`, if set.
/// Uses a `LIKE 'parent/%'` style match. Note: iRODS's `COL_COLL_NAME`
/// stores absolute paths, so this scopes to `parent` and any of its
/// transitive sub-collections.
fn apply_collection_scope(
    q: &mut GenQuery,
    input: &MetaqueryInput,
) -> Result<(), BatonError> {
    if let Some(scope) = &input.collection {
        // Use a like-clause so we match the parent itself plus any
        // descendant collections. `parent/%` doesn't include `parent`
        // alone, so we also match exact equality below if needed —
        // simplest is the union via two conditions, but iRODS's
        // genQuery joins them as AND. Stick with descendants for v1
        // (matches baton's --collection scope which is recursive).
        let pattern = format!("{}%", sql_escape(scope));
        q.add_where(
            ffi::COL_COLL_NAME as i32,
            &format!("like '{}'", pattern),
        )?;
    }
    // Zone scoping ignored at v1 — iRODS's genQuery default queries
    // the local zone; cross-zone querying needs a different API.
    let _ = &input.zone;
    Ok(())
}
